async ({ page, url }) => {
  await page.goto(url);
  await page.waitForSelector('.waste-service-image', { timeout: 30000 });
  const bins = await page.evaluate(() => {
    const results = [];
    const services = document.querySelectorAll('h3.waste-service-name');
    services.forEach(service => {
      const type = service.innerText.trim();
      const parent = service.nextElementSibling;
      if (parent) {
        const dtElements = Array.from(parent.querySelectorAll('dt'));
        const nextCollectionDt = dtElements.find(dt => dt.innerText.includes('Next collection'));
        if (nextCollectionDt) {
          const dateText = nextCollectionDt.nextElementSibling.innerText.trim();
          results.push({ type, dateText });
        }
      }
    });
    return results;
  });
  return bins;
}

