async def get_bins(page):
    # Navigate to the relevant URL (to be provided via input if not fixed)
    # await page.goto(url)

    # Parse bin information from the page structure described in the legacy code
    bins = []
    collect_div = await page.query_selector('div.collect')
    if collect_div:
        paragraphs = await collect_div.query_selector_all('p')
        # Indexing matches legacy logic (Rubbish: 2, Recycling: 4, Garden: 6)
        if len(paragraphs) > 2:
            rubbish_date = await paragraphs[2].query_selector('strong')
            if rubbish_date:
                bins.append({'type': 'Rubbish', 'collectionDate': await rubbish_date.inner_text()})
        if len(paragraphs) > 4:
            recycling_date = await paragraphs[4].query_selector('strong')
            if recycling_date:
                bins.append({'type': 'Recycling', 'collectionDate': await recycling_date.inner_text()})
        if len(paragraphs) > 6:
            garden_date = await paragraphs[6].query_selector('strong')
            if garden_date:
                bins.append({'type': 'Garden', 'collectionDate': await garden_date.inner_text()})
    return bins

