  await page.goto('https://selfservice.rushcliffe.gov.uk/renderform.aspx?t=1242&k=86BDCD8DE8D868B9E23D10842A7A4FE0F1023CCA');
  await page.fill('#FF3518-text', postcode);
  await page.click('#FF3518-find');
  await page.waitForSelector('#FF3518-list');
  const dropdown = page.locator('#FF3518-list');
  const options = await dropdown.locator('option').all();
  let found = false;
  for (const option of options) {
    const val = await option.getAttribute('value');
    if (val && val.includes('U' + uprn)) {
      await dropdown.selectOption(val);
      found = true;
      break;
