async ({ page, url }) => {
  await page.goto(url);
  const data = { bins: [] };
  const sections = await page.locator('.wil_c-content-section_heading').all();
  for (const s of sections) {
    const text = await s.innerText();
    if (text.toLowerCase().includes('bin collections')) {
      const body = s.locator('xpath=following-sibling::div[contains(@class, "c-content-section_body")]');
      const rows = await body.locator('div.u-mt-10').all();
      for (const row of rows) {
        const titleElem = await row.locator('div.u-mb-4').first();
        const title = (await titleElem.innerText()).trim();
        const collections = await row.locator('div.u-mb-2').all();
        for (const c of collections) {
          const cText = (await c.innerText()).toLowerCase();
          if (cText.includes('next collection')) {
            const dateText = cText.replace('next collection - ', '').trim();
            data.bins.push({ type: title, collectionDate: dateText });
          }
        }
        const futureItems = await row.locator('ul.u-mt-4 li').all();
        for (const item of futureItems) {
          const futureDate = (await item.innerText()).trim();
          data.bins.push({ type: title, collectionDate: futureDate });
        }
      }
    }
  }
  return data;
}

